// AUTO-GENERATED by scripts/generate-codex-index.mjs. Do not edit by hand.
//
// Codex portraits — the cinematic high-resolution set generated via the
// openai-codex image backend. Used as the modal portrait in the horse
// detail view (size='xl'); pixel-art from /assets/horses/index.js stays
// in the lineup/grid.
//
// Naming: {breed_prefix}_{lifeStage}_{mood}.png
// Breed prefixes match horse.js BREED_POOL.prefix values:
//   quarter_horse=qh, appaloosa=appy, paint_horse=paint,
//   arabian=arab, thoroughbred=tb, andalusian=andy
//
// Lookup follows the same four-tier fallback chain as the pixel-art set:
//   1. exact: breed + lifeStage + mood
//   2. breed + lifeStage + 'calm' (any-mood fallback)
//   3. breed + lifeStage (any-mood fallback)
//   4. any breed + lifeStage + mood (any-breed fallback)

const FALLBACK_LIFE_STAGE = 'campaigner';
const FALLBACK_BREED = 'quarter_horse';

// Breed id → file prefix. Must match the prefix in BREED_POOL.
const BREED_PREFIX = {
  quarter_horse: 'qh',
  appaloosa: 'appy',
  paint_horse: 'paint',
  arabian: 'arab',
  thoroughbred: 'tb',
  andalusian: 'andy',
};

// Reverse map: prefix → breed id (for the any-breed fallback).
const PREFIX_TO_BREED = Object.fromEntries(
  Object.entries(BREED_PREFIX).map(([k, v]) => [v, k])
);

export const CODEX_PORTRAITS = [
__ENTRIES__
];

const byKey = new Map();           // "breed|lifeStage|mood" -> path
const byBreedStage = new Map();    // "breed|lifeStage" -> [path, ...]
const byLifeStageMood = new Map(); // "lifeStage|mood" -> [path, ...]
const byLifeStage = new Map();     // "lifeStage" -> [path, ...]
const all = [];                    // [path, ...]

for (const p of CODEX_PORTRAITS) {
  if (!p || !p.path) continue;
  byKey.set(`${p.breed}|${p.lifeStage}|${p.mood}`, p.path);
  pushInto(byBreedStage, `${p.breed}|${p.lifeStage}`, p.path);
  pushInto(byLifeStageMood, `${p.lifeStage}|${p.mood}`, p.path);
  pushInto(byLifeStage, p.lifeStage, p.path);
  all.push(p.path);
}

function pushInto(map, key, value) {
  if (!map.has(key)) map.set(key, []);
  map.get(key).push(value);
}

export function getCodexUrl(horse) {
  if (!horse) return null;
  const breed = horse.breed || FALLBACK_BREED;
  const stage = horse.lifeStageId || horse.stageId || FALLBACK_LIFE_STAGE;
  const mood = horse.mood || 'calm';

  return (
    byKey.get(`${breed}|${stage}|${mood}`) ||
    byKey.get(`${breed}|${stage}|calm`) ||
    pick(byBreedStage.get(`${breed}|${stage}`)) ||
    pick(byLifeStageMood.get(`${stage}|${mood}`)) ||
    pick(byLifeStage.get(stage)) ||
    pick(all)
  );
}

// Diagnostic: how many portraits are loaded, exposed so app.js can
// surface progress in the title card status if it wants.
export function codexPortraitCount() {
  return CODEX_PORTRAITS.length;
}

function pick(arr) {
  return arr && arr.length ? arr[0] : null;
}